const express = require('express');
const axios = require('axios');

// Set up Express app
const app = express();

// Set secret key for secure cookie storage
app.set('secretKey', 'your_secret_key_here');

// Store access token in session
app.use(session({
  secret: app.get('secretKey'),
  resave: false,
  saveUninitialized: true
}));

// Redirect to authorization URL
const authUrl = 'https://example.com/oauth/authorize';
const clientId = 'your_client_id_here';
const redirectUri = 'http://localhost:3000/callback';

app.get('/login', (req, res) => {
  const url = `${authUrl}?client_id=${clientId}&redirect_uri=${redirectUri}&response_type=token`;
  res.redirect(url);
});

// Handle authorization callback
app.get('/callback', (req, res) => {
  const token = req.query.access_token;
  if (!token) {
    res.status(401).send('Unauthorized');
  } else {
    // Store access token in session
    req.session.accessToken = token;
    res.redirect('/');
  }
});

// API call using stored access token
app.get('/api/data', (req, res) => {
  const accessToken = req.session.accessToken;
  if (!accessToken) {
    res.status(401).send('Unauthorized');
  } else {
    axios.get('https://example.com/api/data', {
      headers: { Authorization: `Bearer ${accessToken}` }
    })
    .then(response => {
      res.json(response.data);
    })
    .catch(error => {
      console.error(error);
      res.status(500).send('Internal Server Error');
    });
  }
});

// Start Express server
const port = 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});